(window.webpackJsonp=window.webpackJsonp||[]).push([[28],{655:function(n,r){n.exports='\x3c!-- \r\ntitle: 08-文件操作\r\nsort: \r\n--\x3e \r\n# 文件输入输出\r\n\r\n## 标准IO\r\n> `fopen(file, mode)`\r\n> - rwa 读写追\r\n> - b 二进制\r\n> - \\+ 更新模式\r\n> - `fopen()`创建一个缓冲区，并返回指向该结构的指针。\r\n> \r\n> - **w会删除文件中的内容**\r\n> \r\n> `getc() putc()`\r\n> \r\n> - 与`getchar() putchar()`类似。\r\n> \r\n> - `getchar()`为从标准输入中读取字符。\r\n> \r\n> - `getc(fp)`为从fp指定的文件中读取一个字符。\r\n> \r\n> - `putc(ch, fpput)`为把字符ch放入FILE指针`fpout`所制定的文件中\r\n> 由`EOP`确定一个文件是否到末尾\r\n\r\n```c\r\n#include <stdio.h>\r\n#include <stdlib.h>\r\n\r\nint main(int argc, char *argv [])\r\n{\r\n    int ch;\r\n    // 文件指针\r\n    FILE *fp;\r\n    // 打开文件\r\n    if((fp = fopen(argv[1], "r")) == NULL)\r\n    {\r\n        printf("Can\'t open %s.", argv[1]);\r\n    }\r\n    // 输出内容\r\n    while((ch=getc(fp)) != EOF)\r\n        putc(ch, stdout);\r\n    // 关闭文件\r\n    if(fclose(fp) != 0 )\r\n    {\r\n        printf("Error in closing file %s\\n", argv[1]);\r\n    }\r\n}\r\n```\r\n\r\n\r\n\r\n## 文件IO\r\n- `fprint/fscanf()`\r\n  > `fprint(stdout, "%s is best!", argv[1])`\r\n  >\r\n  > 打印至标准输出\r\n  >\r\n  > `fscanf(stdin, "%40s", word);`\r\n  >\r\n  > 接收输入至word\r\n  >\r\n  > `fprintf(fp, "%s\\n", word);`\r\n  >\r\n  > 将 word 输出到文件\r\n  >\r\n  > `fprint(stderr, "Something was wrong.");`\r\n  >\r\n  > `exit()`\r\n  > \r\n  > 抛出异常\r\n\r\n- `rewind(fp)`\r\n  > 返回文件至最开始处\r\n\r\n- `fgets/puts()`\r\n  > 读取文件至换行符、文件结尾EOF或strlen-1\r\n  >\r\n  > `fgets(receive*, strlen, FILE*)`\r\n  > \r\n  > 接受地址，长度，文件指针。\r\n  >\r\n  > 会读取换行符，放在空字符\\0之前。\r\n  >\r\n  > `fputs(send*, FILE*)`\r\n  > \r\n  > 不添加换行符\r\n\r\n## 随机访问\r\n\r\n```c\r\nfseek(FILE*, Mov(L), SEEK_SET);\r\n/*  用于确定光标位置\r\n    第一个参数为文件指针，\r\n    第二个为偏移量（L表示值为Long），\r\n    第三个为起始位置：\r\n    SEEK_SET SEEK_CUR SEEK_END\r\n    文件开头    当前    文件末尾\r\n\r\n    返回值正常为0，超出文件范围则为-1。\r\n*/\r\nftell(FILE*);\r\n// 返回光标距离开头的字节数（适用于以二进制模式打开的情况下钱）\r\n```\r\n\r\n## 其他标准IO函数\r\n\r\n```c\r\n// 把一个字符放回到缓冲区\r\nint ungetc(int c, FILE * fp)\r\n// 刷新缓冲区，把缓冲区所有尚未读写的数据传入fp中\r\nint fflush(FILE * fp);\r\n// 自己建立缓冲区\r\n// 文件指针，缓冲区，模式，缓冲区大小\r\n/* mode：\r\n_IOFBF  完全缓冲\r\n_IOLBF  行缓冲\r\n_IONBF  无缓冲\r\n*/\r\nint setvbuf(FILE * fp, char * buf, int mode, size_t size);\r\n// 二进制模式存数据，浮点不丢失精度\r\n// 数据 类型大小 数据块数量 文件指针\r\nsize_t fwrite(ptr , sizeof(double), size_t nmemb, FILE * fp);\r\nfread(同上);\r\n```\r\n\r\n## 总结\r\n\r\n> `getchar() putchar(输出内容)`\r\n> > 标准输入输出操作一个字符\r\n>\r\n> `getc(*fp) putc(ch, *fp)`\r\n> > 文件单个字符操作\r\n>\r\n> `fgets(目的地址，长度，*fp) fputs(源地址，*fp)`\r\n> > 操作至换行符\r\n>\r\n> `fprint(目标类型，内容) fscanf(读取位置，存储位置)`\r\n> printf与scanf的升级版'}}]);